data.value:
decimal sumFemaleMortPercent = 0;
int countFemaleMortPercent = 0;
decimal sumMaleDeplPercent = 0;
int countMaleDeplPercent = 0;
decimal sumFemaleCullsPercent = 0;
int countFemaleCullsPercent = 0;
decimal sumMaleCullsPercent = 0;
int countMaleCullsPercent = 0;
decimal sumEggsPerFemale = 0;
int countEggsPerFemale = 0;
private void xrTableCell19_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

    // Get values from fields (note: TotalFemalMort has typo in field name)
    decimal openFemale = Convert.ToDecimal(GetCurrentColumnValue("OpenFemale") ?? 0);
    decimal totalFemaleMort = Convert.ToDecimal(GetCurrentColumnValue("TotalFemalMort") ?? 0);

    // Calculate: (TotalFemaleMort × 100) / OpenFemale
    if (openFemale > 0) {
        decimal result = (totalFemaleMort * 100) / openFemale;
        cell.Text = result.ToString("N2") ; // 2 decimal places with %
        // Or without %: result.ToString("F2")
    } else {
        cell.Text = "0.00"; // or "0"
    }
}

private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // Get values for current row
    decimal openFemale = Convert.ToDecimal(GetCurrentColumnValue("OpenFemale") ?? 0);
    decimal totalFemaleMort = Convert.ToDecimal(GetCurrentColumnValue("TotalFemalMort") ?? 0);

    // Calculate mortality percentage for this row
    if (openFemale > 0) {
        decimal rowMortPercent = (totalFemaleMort * 100) / openFemale;
        sumFemaleMortPercent += rowMortPercent;
        countFemaleMortPercent++;
    }

     // Get values for current row
    decimal openMale = Convert.ToDecimal(GetCurrentColumnValue("OpenMale") ?? 0);
    decimal totalMaleDepl = Convert.ToDecimal(GetCurrentColumnValue("TotalMaleDepl") ?? 0);

    // Calculate deployment percentage for this row
    if (openMale > 0) {
        decimal rowDeplPercent = (totalMaleDepl * 100) / openMale;
        sumMaleDeplPercent += rowDeplPercent;
        countMaleDeplPercent++;
    }

      // Get values for current row
    decimal openFemaleCulls = Convert.ToDecimal(GetCurrentColumnValue("OpenFemale") ?? 0);
    decimal totalFemaleCulls = Convert.ToDecimal(GetCurrentColumnValue("TotalFemaleCulls") ?? 0);

    // Calculate culls percentage for this row
    if (openFemale > 0) {
        decimal rowCullsPercent = (totalFemaleCulls * 100) / openFemaleCulls ;
        sumFemaleCullsPercent += rowCullsPercent;
        countFemaleCullsPercent++;
    }

    // Get values for current row
    decimal openMaleCulls = Convert.ToDecimal(GetCurrentColumnValue("OpenMale") ?? 0);
    decimal totalMaleCulls = Convert.ToDecimal(GetCurrentColumnValue("TotalMaleCulls") ?? 0);

    // Calculate culls percentage for this row
    if (openMale > 0) {
        decimal rowCullsPercent = (totalMaleCulls * 100) / openMaleCulls ;
        sumMaleCullsPercent += rowCullsPercent;
        countMaleCullsPercent++;
    }

    // Get values for current row
    decimal openFemaleHat = Convert.ToDecimal(GetCurrentColumnValue("OpenFemale") ?? 0);
    decimal totalHatEggs = Convert.ToDecimal(GetCurrentColumnValue("TotalHatEggs") ?? 0);

    // Calculate eggs per female for this row
    if (openFemale > 0) {
        decimal rowEggsPerFemale = totalHatEggs / openFemaleHat ;
        sumEggsPerFemale += rowEggsPerFemale;
        countEggsPerFemale++;
    }
}

private void xrTableCell43_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
      XRTableCell cell = sender as XRTableCell;

    if (countFemaleMortPercent > 0) {
        decimal avgMortPercent = sumFemaleMortPercent / countFemaleMortPercent;
        cell.Text = avgMortPercent.ToString("N2");
    } else {
        cell.Text = "0.00";
    }
}

